const { createHmac, timingSafeEqual } = require('crypto');
const auth = $input.item.json.headers?.authorization || '';
const token = auth.replace(/^Bearer\s+/i, '').trim();
const secret = $env.JWT_SECRET;
if (!token) { $input.item.json.jwtValid = false; return $input.item; }
const parts = token.split('.');
if (parts.length !== 3) { $input.item.json.jwtValid = false; return $input.item; }
const [h, p, s] = parts;
const expected = createHmac('sha256', secret).update(`${h}.${p}`).digest('base64url');
const eBuf = Buffer.from(expected); const aBuf = Buffer.from(s);
if (eBuf.length !== aBuf.length || !timingSafeEqual(eBuf, aBuf)) { $input.item.json.jwtValid = false; return $input.item; }
const payload = JSON.parse(Buffer.from(p, 'base64url').toString());
if (payload.exp < Math.floor(Date.now() / 1000)) { $input.item.json.jwtValid = false; return $input.item; }
if (!payload.psychologist_id) { $input.item.json.jwtValid = false; return $input.item; }
$input.item.json.jwtValid = true;
$input.item.json.jwtPsychologistId = payload.psychologist_id;
$input.item.json.jwtRole = payload.role;
$input.item.json.patientId = $input.item.json.query?.patient_id || null;
return $input.item;

const row = $input.item.json;
const jwtRole = $('Code - JWT Verify').item.json.jwtRole;
const jwtPsychologistId = $('Code - JWT Verify').item.json.jwtPsychologistId;

// Patient not found
if (!row.id) {
  $input.item.json._notFound = true;
  return $input.item;
}

// Tenant isolation: non-admin can only access own patients (ADR-5)
const isAdmin = jwtRole === 'admin';
const isOwner = row.psychologist_id === jwtPsychologistId;
if (!isAdmin && !isOwner) {
  // Return 404, not 403 — prevents UUID enumeration
  $input.item.json._notFound = true;
  return $input.item;
}

$input.item.json._accessOk = true;
$input.item.json._patientId = row.id;
return $input.item;

const appointments = $input.all().map(r => r.json);
const patient = $('PG - Fetch Patient').item.json;
const patientId = patient.id;
// Store appointments on the item for later merge
return [{ json: { _patientId: patientId, _patient: patient, _appointments: appointments } }];

const hcRow = $input.item.json;
const stored = $('Code - Store Appointments').item.json;
const patient = stored._patient;
const appointments = stored._appointments;
const patientId = stored._patientId;

// Map each HC section from the single-row correlated subquery result.
// json_agg returns null when there are no rows — coalesce to empty array.
const sections = [
  'demographics', 'chief_complaint', 'personal_history', 'family_history',
  'developmental_history', 'psychological_evaluation', 'diagnosis', 'treatment_plan',
  'consentimientos', 'mental_status_exam', 'social_profile', 'personality_profile',
  'clinical_impression'
];

const clinical_history = {};
for (const section of sections) {
  clinical_history[section] = hcRow[section] || [];
}

const exportData = {
  exported_at: new Date().toISOString(),
  patient: {
    id: patient.id,
    first_name: patient.first_name,
    last_name: patient.last_name,
    email: patient.email,
    phone: patient.phone,
    date_of_birth: patient.date_of_birth,
    gender: patient.gender,
    consent_status: patient.consent_status,
    created_at: patient.created_at
  },
  appointments,
  clinical_history
};

return [{ json: { export: JSON.stringify(exportData, null, 2), patient_id: patientId } }];
